1174: int wolfSSL_sk_SSL_CIPHER_find(WOLF_STACK_OF(WOLFSSL_CIPHER)* ciphers,
1175:     const WOLFSSL_CIPHER* cipher)
1176: {
1177:     int ret = WC_NO_ERR_TRACE(WOLFSSL_FATAL_ERROR);
1178: 
1179:     if (ciphers != NULL && cipher != NULL) {
1180:         int i;
1181:         int num = wolfSSL_sk_SSL_CIPHER_num(ciphers);
1182:         WOLFSSL_STACK* next = ciphers;
1183: 
1184:         for (i = 0; (i < num) && (next != NULL); i++) {
1185:             /* Match on SSL/TLS cipher suite values. */
1186:             if ((next->data.cipher.cipherSuite0 == cipher->cipherSuite0) &&
1187:                     (next->data.cipher.cipherSuite == cipher->cipherSuite)) {
1188:                 /* reverse because stack pushed highest on first */
1189:                 ret = num - i;
1190:                 break;
1191:             }
1192:             next = next->next;
1193:         }
1194:     }
1195: 
1196:     return ret;
