6029:             *found = 0;
6030:         }
6031:         if (ret == 0) {
6032:         #if !defined(WOLFSSL_PSK_ONE_ID) && !defined(WOLFSSL_PRIORITIZE_PSK)
6033:             /* Check whether PSK ciphersuite is in SSL. */
6034:             *found = (suite[0] == cipherSuite0) && (suite[1] == cipherSuite);
6035:         #else
6036:             (void)suite;
6037:             /* Check whether PSK ciphersuite is in SSL. */
6038:             {
6039:                 byte s[2] = {
6040:                     cipherSuite0,
6041:                     cipherSuite,
6042:                 };
6043:                 *found = FindSuiteSSL(ssl, s);
6044:             }
6045:         #endif
6046:         }
6047:     }
6048:     if (*found && foundSuite != NULL) {
6049:         foundSuite[0] = cipherSuite0;
6050:         foundSuite[1] = cipherSuite;
6051:     }
6052: 
6053:     return ret;
6054: }
