6056: /* Attempt to find the PSK (not session ticket) that matches.
6057:  *
6058:  * @param [in, out] ssl    The SSL/TLS object.
6059:  * @param [in]      psk    A pre-shared key from the extension.
6060:  * @param [out]     suite  Cipher suite to use with PSK.
6061:  * @param [out]     err    Error code.
6062:  *                         PSK_KEY_ERROR when key is too big or ticket age is
6063:  *                         invalid,
6064:  *                         UNSUPPORTED_SUITE on invalid suite.
6065:  *                         Other error when attempting to derive early secret.
6066:  * @return  1 when a match found - but check error code.
6067:  * @return  0 when no match found.
6068:  */
6069: static int FindPsk(WOLFSSL* ssl, PreSharedKey* psk, const byte* suite, int* err)
6070: {
6071:     int         ret = 0;
6072:     int         found = 0;
6073:     byte        foundSuite[SUITE_LEN];
6074: 
6075:     WOLFSSL_ENTER("FindPsk");
6076: 
6077:     XMEMSET(foundSuite, 0, sizeof(foundSuite));
6078: 
6079:     ret = FindPskSuite(ssl, psk, ssl->arrays->psk_key, &ssl->arrays->psk_keySz,
6080:                        suite, &found, foundSuite);
6081:     if (ret == 0 && found) {
6082:         /* Default to ciphersuite if cb doesn't specify. */
6083:         ssl->options.resuming = 0;
6084:         /* Don't send certificate request when using PSK. */
6085:         ssl->options.verifyPeer = 0;
6086: 
6087:         /* PSK age is always zero. */
6088:         if (psk->ticketAge != 0) {
6089:             ret = PSK_KEY_ERROR;
6090:             WOLFSSL_ERROR_VERBOSE(ret);
6091:         }
6092:         if (ret == 0) {
6093:             /* Set PSK ciphersuite into SSL. */
6094:             ssl->options.cipherSuite0 = foundSuite[0];
6095:             ssl->options.cipherSuite  = foundSuite[1];
6096:             ret = SetCipherSpecs(ssl);
6097:         }
6098:         if (ret == 0) {
6099:             /* Derive the early secret using the PSK. */
6100:             ret = DeriveEarlySecret(ssl);
6101:         }
6102:         if (ret == 0) {
6103:             /* PSK negotiation has succeeded */
6104:             ssl->options.isPSK = 1;
6105:             /* SERVER: using PSK for peer authentication. */
6106:             ssl->options.peerAuthGood = 1;
6107:         }
6108:     }
6109: 
6110:     *err = ret;
6111:     WOLFSSL_LEAVE("FindPsk", found);
6112:     WOLFSSL_LEAVE("FindPsk", ret);
